    def _sort_palette(self, sort_palette, colors):
        """
        Reorders this image's palette according to ``sort_palette``, and
        remaps the pixel data to match. See :py:meth:`~PIL.Image.Image.quantize`
        for the accepted values of ``sort_palette``.
        """
        mode = self.palette.mode
        channels = len(mode)
        palette_bytes = self.palette.palette
        num_colors = min(colors, len(palette_bytes) // channels)

        def color_at(i):
            return tuple(palette_bytes[i * channels : i * channels + channels])

        if callable(sort_palette):
            key = sort_palette
        elif sort_palette == "rgb":
            key = None
        elif sort_palette == "brightness":

            def key(color):
                r, g, b = color[0], color[1], color[2]
                return r * 299 + g * 587 + b * 114

        else:
            raise ValueError(f"Unknown sort_palette method: {sort_palette!r}")

        if key is None:
            order = sorted(range(num_colors), key=color_at)
        else:
            order = sorted(range(num_colors), key=lambda i: key(color_at(i)))

        return self.remap_palette(order)"}

